import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Escape user input to prevent XSS attacks
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handle user input by outputting the escaped value to the response
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome, " + safeUserInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        out.flush();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
